 Begin CmpMap 	# Compound Mapping
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    MapA = 	# First component Mapping
       Begin CmpMap 	# Compound Mapping
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          MapA = 	# First component Mapping
             Begin CmpMap 	# Compound Mapping
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                MapA = 	# First component Mapping
                   Begin SpecMap 	# Conversion between spectral coordinate systems
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Nspec = 1 	# Number of conversion steps
                      Spec1 = "WNTOFR" 	# Convert wave number to frequency
                   End SpecMap
                MapB = 	# Second component Mapping
                   Begin SpecMap 	# Conversion between spectral coordinate systems
                      Nin = 1 	# Number of input coordinates
                   IsA Mapping 	# Mapping between coordinate systems
                      Nspec = 2 	# Number of conversion steps
                      Spec1 = "FRTOEN" 	# Convert frequency to energy
                      Spec2 = "ENTOFR" 	# Convert energy to frequency
                   End SpecMap
             End CmpMap
          MapB = 	# Second component Mapping
             Begin SpecMap 	# Conversion between spectral coordinate systems
                Nin = 1 	# Number of input coordinates
             IsA Mapping 	# Mapping between coordinate systems
                Nspec = 2 	# Number of conversion steps
                Spec1 = "FRTOWV" 	# Convert frequency to wavelength (vacuum)
                Spec2 = "WVTOFR" 	# Convert wavelength (vacuum) to frequency
             End SpecMap
       End CmpMap
    MapB = 	# Second component Mapping
       Begin SpecMap 	# Conversion between spectral coordinate systems
          Nin = 1 	# Number of input coordinates
       IsA Mapping 	# Mapping between coordinate systems
          Nspec = 1 	# Number of conversion steps
          Spec1 = "FRTOWN" 	# Convert frequency to wave number
       End SpecMap
 End CmpMap
